'use client';

import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';

interface AnimationContextValue {
  /** Whether animations are enabled (respects prefers-reduced-motion) */
  animationsEnabled: boolean;
  /** Whether the user prefers reduced motion */
  prefersReducedMotion: boolean;
}

const AnimationContext = createContext<AnimationContextValue>({
  animationsEnabled: true,
  prefersReducedMotion: false,
});

interface AnimationProviderProps {
  children: React.ReactNode;
}

/**
 * AnimationProvider
 *
 * Manages animation state across the application.
 * Respects the user's prefers-reduced-motion OS setting.
 * When reduced motion is preferred, entrance animations and particle effects
 * are disabled while page transitions and interactive feedback remain active.
 *
 * @see Requirement 13.5
 */
export function AnimationProvider({ children }: AnimationProviderProps) {
  const [prefersReducedMotion, setPrefersReducedMotion] = useState(false);

  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)');
    setPrefersReducedMotion(mediaQuery.matches);

    const handler = (event: MediaQueryListEvent) => {
      setPrefersReducedMotion(event.matches);
    };

    mediaQuery.addEventListener('change', handler);
    return () => mediaQuery.removeEventListener('change', handler);
  }, []);

  const value: AnimationContextValue = useMemo(
    () => ({
      animationsEnabled: !prefersReducedMotion,
      prefersReducedMotion,
    }),
    [prefersReducedMotion]
  );

  return (
    <AnimationContext.Provider value={value}>
      {children}
    </AnimationContext.Provider>
  );
}

/**
 * useAnimation hook
 *
 * Returns the current animation context including whether animations are enabled
 * and whether the user prefers reduced motion.
 */
export function useAnimation(): AnimationContextValue {
  return useContext(AnimationContext);
}

'use client';

import React, { createContext, useCallback, useContext, useEffect, useMemo, useRef, useState } from 'react';

type ConnectionStatus = 'connected' | 'connecting' | 'disconnected' | 'polling-fallback';

interface SocketContextValue {
  /** Current connection status */
  status: ConnectionStatus;
  /** Whether the socket is connected (websocket or polling) */
  isConnected: boolean;
  /** Whether we're in degraded polling mode */
  isDegraded: boolean;
  /** Subscribe to a channel */
  subscribe: (channel: string) => void;
  /** Unsubscribe from a channel */
  unsubscribe: (channel: string) => void;
}

const SocketContext = createContext<SocketContextValue>({
  status: 'disconnected',
  isConnected: false,
  isDegraded: false,
  subscribe: () => {},
  unsubscribe: () => {},
});

interface SocketProviderProps {
  children: React.ReactNode;
}

/**
 * SocketProvider
 *
 * Manages the Socket.IO websocket connection for realtime updates.
 * Implements exponential backoff reconnection (1s start, 2x factor, 30s max, 10 attempts).
 * Falls back to HTTP polling after exhausting reconnection attempts.
 *
 * The actual Socket.IO connection is initialized lazily when a component subscribes
 * to a channel, keeping the initial page load lightweight.
 *
 * @see Requirements 15.1, 15.2, 15.4, 15.7
 */
export function SocketProvider({ children }: SocketProviderProps) {
  const [status, setStatus] = useState<ConnectionStatus>('disconnected');
  const subscribedChannels = useRef<Set<string>>(new Set());

  const subscribe = useCallback((channel: string) => {
    subscribedChannels.current.add(channel);
    // Socket connection will be initialized when needed by specific feature components
    // This provider manages the connection lifecycle
  }, []);

  const unsubscribe = useCallback((channel: string) => {
    subscribedChannels.current.delete(channel);
  }, []);

  const value: SocketContextValue = useMemo(
    () => ({
      status,
      isConnected: status === 'connected' || status === 'polling-fallback',
      isDegraded: status === 'polling-fallback',
      subscribe,
      unsubscribe,
    }),
    [status, subscribe, unsubscribe]
  );

  return (
    <SocketContext.Provider value={value}>
      {children}
    </SocketContext.Provider>
  );
}

/**
 * useSocket hook
 *
 * Returns the current socket context including connection status and channel management.
 */
export function useSocket(): SocketContextValue {
  return useContext(SocketContext);
}

