                />

                {AUTH_LINKS.map((link) => (
                  <MobileNavItem
                    key={link.href}
                    link={link}
                    isActive={isActive(link.href)}
                    onClick={() => setIsMobileMenuOpen(false)}
                  />
                ))}

                {/* Play Now CTA */}
                <Link
                  href="/play"
                  onClick={() => setIsMobileMenuOpen(false)}
                  className="mt-3 px-4 py-3 font-bold text-center uppercase tracking-wide transition-all duration-150 active:translate-y-[1px] focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2"
                  style={{
                    backgroundColor: GAMING_THEME.buttonBg,
                    color: GAMING_THEME.buttonText,
                    border: `2px solid ${GAMING_THEME.border}`,
                    boxShadow: GAMING_THEME.buttonGlow,
                    fontFamily: neoBrutalism.typography.body.family,
                    borderRadius: '4px',
                  }}
                >
                  Play Now
                </Link>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </>
  );
}

/** Desktop navigation link item */
function NavItem({
  link,
  isActive: active,
}: {
  link: NavLink;
  isActive: boolean;
}) {
  return (
    <Link
      href={link.href}
      className="group relative px-3 py-2 text-sm font-medium transition-colors duration-150 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 rounded-sm"
      style={{
        color: active ? GAMING_THEME.linkActive : GAMING_THEME.linkInactive,
        fontFamily: neoBrutalism.typography.body.family,
      }}
      aria-current={active ? 'page' : undefined}
      onMouseEnter={(e) => {
        if (!active) {
          (e.currentTarget as HTMLElement).style.color = GAMING_THEME.linkHover;
        }
      }}
      onMouseLeave={(e) => {
        if (!active) {
          (e.currentTarget as HTMLElement).style.color = GAMING_THEME.linkInactive;
        }
      }}
    >
      {link.label}
      {active && (
        <span
          className="absolute bottom-0 left-3 right-3 h-[2px]"
          style={{
            backgroundColor: GAMING_THEME.cyan,
            boxShadow: GAMING_THEME.activeGlow,
          }}
          aria-hidden="true"
        />
      )}
    </Link>
  );
}

/** Mobile navigation link item */
function MobileNavItem({
  link,
  isActive: active,
  onClick,
}: {
  link: NavLink;
  isActive: boolean;
  onClick: () => void;
}) {
  return (
    <Link
      href={link.href}
      onClick={onClick}
      className="px-4 py-3 text-base font-medium transition-colors duration-150 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 rounded-sm"
      style={{
        color: active ? GAMING_THEME.linkActive : GAMING_THEME.linkInactive,
        backgroundColor: active ? 'rgba(0, 229, 255, 0.08)' : 'transparent',
        borderLeft: active
          ? `3px solid ${GAMING_THEME.cyan}`
          : '3px solid transparent',
        fontFamily: neoBrutalism.typography.body.family,
      }}
      aria-current={active ? 'page' : undefined}
    >
      {link.label}
    </Link>
  );
}

/** Perfect World Logo SVG */
function PerfectWorldLogo({ color }: { color: string }) {
