  });

  it('all links are keyboard-focusable (have href)', () => {
    render(<NavigationBar />);
    const links = screen.getAllByRole('link');
    for (const link of links) {
      expect(link).toHaveAttribute('href');
    }
  });

  it('renders spacer div to prevent content overlap', () => {
    const { container } = render(<NavigationBar />);
    const spacer = container.querySelector('.h-16[aria-hidden="true"]');
    expect(spacer).toBeInTheDocument();
  });
});

'use client';

import React, { useState } from 'react';
import { useTheme, neoBrutalism } from '@perfect-world/ui';

/** Validates email format using a standard regex pattern */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

const quickLinks = [
  { label: 'Download', href: '/download' },
  { label: 'News', href: '/news' },
  { label: 'Rankings', href: '/rankings' },
  { label: 'Wiki', href: '/wiki' },
];

const supportLinks = [
