                style={{
                  color: colors.accentCrimson,
                  fontSize: '12px',
                  marginTop: '6px',
                }}
              >
                {error}
              </p>
            )}
            {success && (
              <p
                role="status"
                style={{
                  color: colors.accentCyan,
                  fontSize: '12px',
                  marginTop: '6px',
                }}
              >
                Successfully subscribed! Thank you.
              </p>
            )}
          </form>
        </div>
      </div>

      {/* Bottom bar */}
      <div
        style={{
          marginTop: '40px',
          paddingTop: '20px',
          borderTop: `${borderWidth} solid ${colors.border}`,
          textAlign: 'center',
          color: colors.textSecondary,
          fontSize: '14px',
        }}
      >
        © {new Date().getFullYear()} Perfect World. All rights reserved.
      </div>

      {/* Responsive + hover styles */}
      <style>{`
        .footer-grid {
          grid-template-columns: 2fr 1fr 1fr 1.5fr;
        }
        @media (max-width: 1024px) {
          .footer-grid {
            grid-template-columns: 1fr 1fr !important;
          }
        }
        @media (max-width: 768px) {
          .footer-grid {
            grid-template-columns: 1fr !important;
          }
        }

        .footer-link:hover {
          color: var(--accent-cyan) !important;
        }

        .social-btn:hover {
          border-color: var(--accent-cyan) !important;
          color: var(--accent-cyan) !important;
          box-shadow: 0 0 8px var(--accent-cyan-40), inset 0 0 4px var(--accent-cyan-20) !important;
        }

        .newsletter-input:focus {
          border-color: var(--accent-cyan) !important;
          box-shadow: 0 0 8px var(--accent-cyan-40) !important;
        }

        .subscribe-btn:hover {
          box-shadow: 0 0 16px var(--accent-cyan-60), 0 0 4px var(--accent-cyan-40) !important;
          transform: translateY(-1px);
        }

        .subscribe-btn:active {
          transform: translateY(0);
        }
      `}</style>
    </footer>
  );
}

import { io, Socket } from 'socket.io-client';
import { computeBackoffDelay, DEFAULT_BACKOFF_CONFIG, type BackoffConfig } from './backoff';
import {
  type ConnectionState,
  type RealtimeClientConfig,
  type EventCallback,
  type SocketChannel,
  POLLABLE_CHANNELS,
} from './types';

/**
 * RealtimeClient wraps Socket.IO with:
 * - JWT-authenticated websocket connections (5s timeout)
 * - Exponential backoff reconnection (1s start, 2x factor, 30s max, 10 attempts)
 * - HTTP polling fallback after 10 failed attempts (30s interval)
 * - Degraded-mode state tracking
 */
export class RealtimeClient {
  private socket: Socket | null = null;
  private connectionState: ConnectionState = 'disconnected';
  private reconnectAttempt = 0;
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
  private pollingTimers: Map<string, ReturnType<typeof setInterval>> = new Map();
  private listeners: Map<string, Set<EventCallback>> = new Map();
  private subscribedChannels: Set<SocketChannel> = new Set();
  private backoffConfig: BackoffConfig = DEFAULT_BACKOFF_CONFIG;

  private readonly config: Required<RealtimeClientConfig>;

  constructor(config: RealtimeClientConfig) {
    this.config = {
      connectionTimeout: 5000,
      pollingInterval: 30000,
      ...config,
    };
  }

  /** Get the current connection state */
  getConnectionState(): ConnectionState {
    return this.connectionState;
  }

  /** Check if the client is in degraded (polling) mode */
  isDegraded(): boolean {
    return this.connectionState === 'degraded';
  }

  /** Connect to the websocket server */
  connect(): void {
    const token = this.config.getToken();
    if (!token) {
      this.setConnectionState('disconnected');
      return;
    }

    this.setConnectionState('connecting');
    this.reconnectAttempt = 0;

    this.socket = io(this.config.url, {
      auth: { token },
      timeout: this.config.connectionTimeout,
      reconnection: false, // We handle reconnection manually for backoff control
      transports: ['websocket'],
    });

    this.setupSocketListeners();
  }

  /** Disconnect from the websocket server and stop all polling */
  disconnect(): void {
    this.clearReconnectTimer();
    this.stopAllPolling();

    if (this.socket) {
      this.socket.removeAllListeners();
      this.socket.disconnect();
      this.socket = null;
    }

    this.setConnectionState('disconnected');
  }

  /** Subscribe to a channel */
  subscribe(channel: SocketChannel): void {
    this.subscribedChannels.add(channel);

    if (this.socket?.connected) {
      this.socket.emit('subscribe', channel);
    }

    // If in degraded mode, start polling for this channel if pollable
    if (this.connectionState === 'degraded' && POLLABLE_CHANNELS.includes(channel)) {
      this.startPollingForChannel(channel);
    }
  }

  /** Unsubscribe from a channel */
  unsubscribe(channel: SocketChannel): void {
    this.subscribedChannels.delete(channel);

    if (this.socket?.connected) {
      this.socket.emit('unsubscribe', channel);
    }

    this.stopPollingForChannel(channel);
  }

  /** Register an event listener */
  on<T = unknown>(event: string, callback: EventCallback<T>): void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(callback as EventCallback);

    // Also register on the socket if connected
    if (this.socket?.connected) {
      this.socket.on(event, callback as EventCallback);
    }
  }

  /** Remove an event listener */
  off<T = unknown>(event: string, callback: EventCallback<T>): void {
    const eventListeners = this.listeners.get(event);
    if (eventListeners) {
      eventListeners.delete(callback as EventCallback);
    }

    if (this.socket) {
      this.socket.off(event, callback as EventCallback);
    }
  }

  /** Emit data to listeners for a given event */
  private emit(event: string, data: unknown): void {
    const eventListeners = this.listeners.get(event);
    if (eventListeners) {
      eventListeners.forEach((cb) => cb(data));
    }
  }

  private setupSocketListeners(): void {
    if (!this.socket) return;

    this.socket.on('connect', () => {
      this.reconnectAttempt = 0;
      this.setConnectionState('connected');
      this.stopAllPolling();

      // Re-subscribe to all channels
      this.subscribedChannels.forEach((channel) => {
        this.socket!.emit('subscribe', channel);
      });

      // Re-register all event listeners on the socket
      this.listeners.forEach((callbacks, event) => {
        callbacks.forEach((cb) => {
          this.socket!.on(event, cb);
        });
      });
    });

    this.socket.on('disconnect', (reason) => {
      if (reason === 'io client disconnect') {
        // Intentional disconnect, don't reconnect
        return;
      }
      this.attemptReconnect();
    });

    this.socket.on('connect_error', () => {
      this.attemptReconnect();
    });
  }

  private attemptReconnect(): void {
    this.reconnectAttempt++;

    const delay = computeBackoffDelay(this.reconnectAttempt, this.backoffConfig);

    if (delay === null) {
      // Exhausted all reconnection attempts, fall back to polling
      this.enterDegradedMode();
      return;
    }

    this.setConnectionState('reconnecting');
    this.clearReconnectTimer();

    this.reconnectTimer = setTimeout(() => {
      const token = this.config.getToken();
      if (!token) {
        this.setConnectionState('disconnected');
        return;
      }

      // Clean up old socket
      if (this.socket) {
        this.socket.removeAllListeners();
        this.socket.disconnect();
      }

      // Create new connection attempt
      this.socket = io(this.config.url, {
        auth: { token },
        timeout: this.config.connectionTimeout,
        reconnection: false,
        transports: ['websocket'],
      });

      this.setupSocketListeners();
    }, delay);
  }

  private enterDegradedMode(): void {
    this.setConnectionState('degraded');

    // Start polling for all subscribed pollable channels
    this.subscribedChannels.forEach((channel) => {
      if (POLLABLE_CHANNELS.includes(channel)) {
        this.startPollingForChannel(channel);
      }
    });
  }

  private startPollingForChannel(channel: SocketChannel): void {
    // Don't start duplicate polling
    if (this.pollingTimers.has(channel)) return;

    // Immediately fetch once
    this.pollChannel(channel);

    // Then set up interval
    const timer = setInterval(() => {
      this.pollChannel(channel);
    }, this.config.pollingInterval);

    this.pollingTimers.set(channel, timer);
  }

  private stopPollingForChannel(channel: SocketChannel): void {
    const timer = this.pollingTimers.get(channel);
    if (timer) {
      clearInterval(timer);
      this.pollingTimers.delete(channel);
    }
  }

  private stopAllPolling(): void {
    this.pollingTimers.forEach((timer) => clearInterval(timer));
    this.pollingTimers.clear();
  }

  private async pollChannel(channel: SocketChannel): Promise<void> {
    try {
      const token = this.config.getToken();
      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
      };
      if (token) {
        headers['Authorization'] = `Bearer ${token}`;
      }

      const response = await fetch(
        `${this.config.apiBaseUrl}/realtime/poll/${channel}`,
        { headers },
      );

      if (response.ok) {
        const data = await response.json();
        this.emit(channel, data);
      }
    } catch {
      // Silently fail on polling errors - will retry on next interval
    }
  }

  private setConnectionState(state: ConnectionState): void {
    if (this.connectionState !== state) {
      this.connectionState = state;
      this.emit('connection-state-change', state);
    }
  }

  private clearReconnectTimer(): void {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
  }
}

/**
 * Exponential backoff delay computation for websocket reconnection.
 *
 * Formula: min(baseDelay * 2^(attempt - 1), maxDelay)
 *
 * This is a pure function exported separately for property-based testing.
 */

export interface BackoffConfig {
  /** Base delay in milliseconds (default: 1000) */
  baseDelay: number;
  /** Multiplier factor (default: 2) */
  factor: number;
  /** Maximum delay cap in milliseconds (default: 30000) */
  maxDelay: number;
  /** Maximum number of reconnection attempts (default: 10) */
  maxAttempts: number;
}

export const DEFAULT_BACKOFF_CONFIG: BackoffConfig = {
  baseDelay: 1000,
  factor: 2,
  maxDelay: 30000,
  maxAttempts: 10,
};

/**
 * Computes the reconnection delay for a given attempt number.
 *
 * @param attempt - The attempt number (1-indexed, 1 <= attempt <= maxAttempts)
 * @param config - Backoff configuration parameters
 * @returns The delay in milliseconds, or null if attempt exceeds maxAttempts
 */
export function computeBackoffDelay(
  attempt: number,
  config: BackoffConfig = DEFAULT_BACKOFF_CONFIG,
): number | null {
  if (attempt < 1 || attempt > config.maxAttempts) {
    return null;
  }

  const delay = config.baseDelay * Math.pow(config.factor, attempt - 1);
  return Math.min(delay, config.maxDelay);
}

/**
 * Realtime communication types for the Perfect World SDK.
 */

/** Available Socket.IO channels for subscription */
export enum SocketChannel {
  SERVER_STATUS = 'server-status',
  MARKETPLACE_UPDATES = 'marketplace-updates',
  GUILD_EVENTS = 'guild-events',
  TERRITORY_WAR = 'territory-war',
  PERSONAL_NOTIFICATIONS = 'personal-notifications',
}

/** Channels that support HTTP polling fallback */
export const POLLABLE_CHANNELS: SocketChannel[] = [
  SocketChannel.SERVER_STATUS,
  SocketChannel.MARKETPLACE_UPDATES,
  SocketChannel.TERRITORY_WAR,
];

/** Connection state of the realtime client */
export type ConnectionState = 'connected' | 'connecting' | 'reconnecting' | 'disconnected' | 'degraded';

/** Server status event payload */
export interface ServerStatusEvent {
  serverId: string;
  name: string;
  status: 'online' | 'offline' | 'busy' | 'maintenance';
  playerCount: number;
  maxPlayers: number;
  ping: number;
  maintenanceETA?: string;
}

/** Territory update event payload */
export interface TerritoryUpdateEvent {
  territoryId: string;
  newOwnerId: string | null;
  guildName: string | null;
  guildColor: string;
  captureDate: string;
  isUnderSiege: boolean;
}

/** Marketplace event payload */
export interface MarketplaceEvent {
  type: 'listing_created' | 'listing_sold' | 'auction_bid' | 'price_change';
  listingId: string;
  itemId: string;
  price: number;
  timestamp: string;
}

/** Configuration for the RealtimeClient */
export interface RealtimeClientConfig {
  /** WebSocket server URL */
  url: string;
  /** Function that returns the current JWT token */
  getToken: () => string | null;
  /** Base URL for HTTP polling fallback */
  apiBaseUrl: string;
  /** Connection timeout in milliseconds (default: 5000) */
  connectionTimeout?: number;
  /** Polling interval in milliseconds for fallback mode (default: 30000) */
  pollingInterval?: number;
}

/** Event listener callback type */
export type EventCallback<T = unknown> = (data: T) => void;

/** Realtime client event map */
export interface RealtimeEventMap {
  'connection-state-change': ConnectionState;
  'server-status': ServerStatusEvent;
  'marketplace-updates': MarketplaceEvent;
  'guild-events': unknown;
  'territory-war': TerritoryUpdateEvent;
  'personal-notifications': unknown;
}

/**
 * React hook for easy integration of the RealtimeClient.
 *
 * Provides connection state, degraded mode indicator, and
 * channel subscription management.
 */

// Note: This module uses React as a peer dependency.
// It will only work in React environments.

import { useEffect, useRef, useState, useCallback } from 'react';
import { RealtimeClient } from './client';
import type { ConnectionState, RealtimeClientConfig, EventCallback, SocketChannel } from './types';

export interface UseRealtimeOptions {
  /** RealtimeClient configuration */
  config: RealtimeClientConfig;
  /** Channels to subscribe to on connect */
  channels?: SocketChannel[];
  /** Whether to auto-connect on mount (default: true) */
  autoConnect?: boolean;
}

export interface UseRealtimeReturn {
  /** Current connection state */
  connectionState: ConnectionState;
  /** Whether the client is in degraded (polling) mode */
  isDegraded: boolean;
  /** Whether the client is connected via websocket */
  isConnected: boolean;
  /** Connect to the realtime server */
  connect: () => void;
  /** Disconnect from the realtime server */
  disconnect: () => void;
  /** Subscribe to a channel */
  subscribe: (channel: SocketChannel) => void;
  /** Unsubscribe from a channel */
  unsubscribe: (channel: SocketChannel) => void;
  /** Register an event listener */
  on: <T = unknown>(event: string, callback: EventCallback<T>) => void;
  /** Remove an event listener */
  off: <T = unknown>(event: string, callback: EventCallback<T>) => void;
}

export function useRealtime(options: UseRealtimeOptions): UseRealtimeReturn {
  const { config, channels = [], autoConnect = true } = options;
  const clientRef = useRef<RealtimeClient | null>(null);
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');

  // Initialize client once
  if (!clientRef.current) {
    clientRef.current = new RealtimeClient(config);
  }

  useEffect(() => {
    const client = clientRef.current!;

    // Listen for connection state changes
    const handleStateChange: EventCallback<ConnectionState> = (state) => {
      setConnectionState(state);
    };
    client.on('connection-state-change', handleStateChange);

    // Auto-connect if enabled
    if (autoConnect) {
      client.connect();
    }

    // Subscribe to initial channels
    channels.forEach((channel) => client.subscribe(channel));

    return () => {
      client.off('connection-state-change', handleStateChange);
      client.disconnect();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const connect = useCallback(() => {
    clientRef.current?.connect();
  }, []);

  const disconnect = useCallback(() => {
    clientRef.current?.disconnect();
  }, []);

  const subscribe = useCallback((channel: SocketChannel) => {
    clientRef.current?.subscribe(channel);
  }, []);

  const unsubscribe = useCallback((channel: SocketChannel) => {
    clientRef.current?.unsubscribe(channel);
  }, []);

  const on = useCallback(<T = unknown>(event: string, callback: EventCallback<T>) => {
    clientRef.current?.on(event, callback);
  }, []);

  const off = useCallback(<T = unknown>(event: string, callback: EventCallback<T>) => {
    clientRef.current?.off(event, callback);
  }, []);

  return {
    connectionState,
    isDegraded: connectionState === 'degraded',
    isConnected: connectionState === 'connected',
    connect,
    disconnect,
    subscribe,
    unsubscribe,
    on,
    off,
  };
}

