import { describe, it, expect } from 'vitest';
import fc from 'fast-check';
import { neoBrutalism } from '@perfect-world/ui/styles/tokens';

/**
 * Property-Based Tests for HeroSection
 *
 * Validates universal properties that should hold across all valid inputs.
 * Uses fast-check to generate arbitrary test cases.
 *
 * **Validates: Requirements 2.1, 2.2, 2.8, 2.9, 2.10, 2.11**
 */

describe('HeroSection - Property-Based Tests', () => {
  /**
   * Property: Heading Font Size Compliance
   *
   * For any viewport width, the computed heading font size SHALL be:
   * - At least 72px on desktop viewports (>=1024px)
   * - At least 36px on mobile viewports (<768px)
   * - Responsive between breakpoints
   *
   * **Validates: Requirement 2.1**
   */
  describe('Property: Heading Font Size Compliance', () => {
    it('should compute correct heading size for desktop viewports', () => {
      fc.assert(
        fc.property(fc.integer({ min: 1024, max: 2560 }), (viewportWidth) => {
          // Parse clamp(36px, 10vw, 72px)
          const vwValue = (viewportWidth * 10) / 100;
          const computedSize = Math.max(36, Math.min(vwValue, 72));

          // Desktop should be at least 72px
          expect(computedSize).toBeGreaterThanOrEqual(72);
        })
      );
    });

    it('should compute correct heading size for mobile viewports', () => {
      fc.assert(
        fc.property(fc.integer({ min: 320, max: 767 }), (viewportWidth) => {
          // Parse clamp(36px, 10vw, 72px)
          const vwValue = (viewportWidth * 10) / 100;
          const computedSize = Math.max(36, Math.min(vwValue, 72));

          // Mobile should be at least 36px
          expect(computedSize).toBeGreaterThanOrEqual(36);
        })
      );
    });

    it('should maintain responsive scaling across all breakpoints', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 320, max: 2560 }),
          (viewportWidth) => {
            // Parse clamp(36px, 10vw, 72px)
            const vwValue = (viewportWidth * 10) / 100;
            const computedSize = Math.max(36, Math.min(vwValue, 72));

            // Size should always be between min and max
            expect(computedSize).toBeGreaterThanOrEqual(36);
            expect(computedSize).toBeLessThanOrEqual(72);
          }
        )
      );
    });
  });

  /**
   * Property: Neo Brutalism Border and Shadow Enforcement
   *
   * For any CTA button in the hero section, the computed styles SHALL include:
   * - Border width of at least 2px
   * - Shadow offset of at least 4px in both X and Y axes
   *
   * **Validates: Requirement 2.3 (Button styling)**
   */
  describe('Property: Neo Brutalism Button Styling', () => {
    it('should enforce minimum 2px border on all CTA buttons', () => {
      fc.assert(
        fc.property(fc.constant(null), () => {
          const borderWidth = parseInt(neoBrutalism.borders.width.default);
          expect(borderWidth).toBeGreaterThanOrEqual(2);
        })
      );
    });

    it('should enforce minimum 4px shadow offset on buttons', () => {
      fc.assert(
        fc.property(fc.constant(null), () => {
          const shadowOffset = neoBrutalism.shadows.offset.md;
          const [x, y] = shadowOffset.split(' ').map((v) => parseInt(v));
          expect(x).toBeGreaterThanOrEqual(4);
          expect(y).toBeGreaterThanOrEqual(4);
        })
      );
    });
  });

  /**
   * Property: Player Count Display Formatting
   *
   * For any valid player count (0 to 999,999,999), the display SHALL:
   * - Format with thousands separators (commas)
   * - Display "X players online" text
   * - Never display negative numbers
   *
   * **Validates: Requirement 2.6 (Server status integration)**
   */
  describe('Property: Player Count Display Formatting', () => {
    it('should format all valid player counts with thousands separators', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 0, max: 999999999 }),
          (playerCount) => {
            const formatted = playerCount.toLocaleString();
            // Should contain commas for numbers >= 1000
            if (playerCount >= 1000) {
              expect(formatted).toMatch(/,/);
            }
            // Should not contain negative sign
            expect(formatted).not.toMatch(/-/);
          }
        )
      );
    });

    it('should never display negative player counts', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 0, max: 999999999 }),
          (playerCount) => {
            expect(playerCount).toBeGreaterThanOrEqual(0);
          }
        )
      );
    });
  });

  /**
   * Property: Parallax Layer Speed Ratios
   *
   * For any parallax layer configuration, the speed ratios SHALL:
   * - Be distinct between layers (layer 1 != layer 2)
   * - Maintain minimum 30fps performance
   * - Have speed values between 0 and 1 (representing scroll multipliers)
   *
   * **Validates: Requirement 2.8 (Parallax scrolling)**
   */
  describe('Property: Parallax Layer Configuration', () => {
    it('should have distinct speed ratios for different layers', () => {
      fc.assert(
        fc.property(fc.constant(null), () => {
          const layer1Speed = 0.3;
          const layer2Speed = 0.5;
          expect(layer1Speed).not.toEqual(layer2Speed);
        })
      );
    });

    it('should maintain valid speed multipliers between 0 and 1', () => {
      fc.assert(
        fc.property(
          fc.float({ min: 0, max: 1, noNaN: true }),
          (speed) => {
            expect(speed).toBeGreaterThanOrEqual(0);
            expect(speed).toBeLessThanOrEqual(1);
          }
        )
      );
    });
  });

  /**
   * Property: WebGL Fallback Behavior
   *
   * For any device capability state, the hero section SHALL:
   * - Render 3D scene on WebGL-capable devices
   * - Fall back to static image on non-WebGL devices
   * - Never fail to render content
   *
   * **Validates: Requirement 2.10 (WebGL fallback)**
   */
  describe('Property: WebGL Fallback Behavior', () => {
    it('should handle all boolean WebGL support states', () => {
      fc.assert(
        fc.property(fc.boolean(), (webGLSupported) => {
          // Should not throw regardless of WebGL support
          expect(() => {
            // Simulating component render logic
            if (webGLSupported) {
              // Render 3D scene
            } else {
              // Render fallback image
            }
          }).not.toThrow();
        })
      );
    });
  });

  /**
   * Property: Loading Placeholder Dimensions
   *
   * For any loading state, the placeholder SHALL:
   * - Preserve section layout dimensions (100vh height)
   * - Display within reasonable time
   * - Not cause layout shift
   *
   * **Validates: Requirement 2.11 (Loading placeholder)**
   */
  describe('Property: Loading Placeholder Dimensions', () => {
    it('should preserve full viewport height during loading', () => {
      fc.assert(
        fc.property(fc.constant(null), () => {
          const heroHeight = '100vh';
          // Should always be full viewport height
          expect(heroHeight).toBe('100vh');
        })
      );
    });

    it('should maintain consistent z-index layering', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 0, max: 100 }),
          (zIndex) => {
            // Z-index values should be non-negative
            expect(zIndex).toBeGreaterThanOrEqual(0);
          }
        )
      );
    });
  });

  /**
   * Property: Color Palette Consistency
   *
   * For any color from the Neo Brutalism palette, the value SHALL:
   * - Be a valid hex color code
   * - Be consistent across dark/light modes
   * - Not be undefined or null
   *
   * **Validates: Requirement 1.5 (Dark mode colors)**
   */
  describe('Property: Color Palette Consistency', () => {
    it('should have valid hex color codes for all dark mode colors', () => {
      fc.assert(
        fc.property(fc.constant(null), () => {
          const darkColors = Object.values(neoBrutalism.colors.dark);
          darkColors.forEach((color) => {
            expect(color).toBeDefined();
            expect(color).toMatch(/^#[0-9A-F]{6}$/i);
          });
        })
      );
    });

    it('should have valid hex color codes for all light mode colors', () => {
      fc.assert(
        fc.property(fc.constant(null), () => {
          const lightColors = Object.values(neoBrutalism.colors.light);
          lightColors.forEach((color) => {
            expect(color).toBeDefined();
            expect(color).toMatch(/^#[0-9A-F]{6}$/i);
          });
        })
      );
    });
  });

  /**
   * Property: Button Link Validity
   *
   * For any CTA button, the href attribute SHALL:
   * - Be a non-empty string
   * - Start with '/' for internal routes
   * - Not contain invalid characters
   *
   * **Validates: Requirement 2.3, 2.4 (Button links)**
   */
  describe('Property: Button Link Validity', () => {
    it('should have valid internal route links', () => {
      fc.assert(
        fc.property(
          fc.oneof(
            fc.constant('/play'),
            fc.constant('/download'),
            fc.constant('#')
          ),
          (href) => {
            expect(href).toBeDefined();
            expect(href.length).toBeGreaterThan(0);
            // Should be either internal route or anchor
            expect(href).toMatch(/^(\/|#)/);
          }
        )
      );
    });
  });

  /**
   * Property: Responsive Breakpoint Consistency
   *
   * For any viewport width, the layout SHALL:
   * - Use correct breakpoint (sm: 768px, md: 1024px, lg: 1440px)
   * - Apply appropriate styles for that breakpoint
   * - Not have overlapping breakpoint ranges
   *
   * **Validates: Requirement 14.1 (Responsive design)**
   */
  describe('Property: Responsive Breakpoint Consistency', () => {
    it('should have non-overlapping breakpoint ranges', () => {
      fc.assert(
        fc.property(fc.constant(null), () => {
          const breakpoints = [
            parseInt(neoBrutalism.layout.breakpoints.sm),
            parseInt(neoBrutalism.layout.breakpoints.md),
            parseInt(neoBrutalism.layout.breakpoints.lg),
            parseInt(neoBrutalism.layout.breakpoints.xl),
          ];

          // Each breakpoint should be less than the next
          for (let i = 0; i < breakpoints.length - 1; i++) {
            expect(breakpoints[i]).toBeLessThan(breakpoints[i + 1]);
          }
        })
      );
    });

    it('should support full viewport range from 320px to 2560px', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 320, max: 2560 }),
          (viewportWidth) => {
            // Should be within supported range
            expect(viewportWidth).toBeGreaterThanOrEqual(320);
            expect(viewportWidth).toBeLessThanOrEqual(2560);
          }
        )
      );
    });
  });
});

'use client';

import React, { useEffect, useState, useCallback } from 'react';
import { ServerStatusEvent, SocketChannel } from '@perfect-world/sdk';
import { useSocket } from '@/providers/SocketProvider';
import { Card, Badge, Skeleton } from '@perfect-world/ui';

interface ServerStatusWidgetProps {
  /** Whether to show the online player count in the hero section (30s update) */
  showOnlineCount?: boolean;
  /** Maximum number of servers to display (4-20) */
  maxServers?: number;
}

/**
 * ServerStatusWidget
 *
 * Displays realtime server status information including:
 * - Server name, status indicator (online/offline/busy/maintenance)
 * - Current player count and ping latency
 * - Busy status when playerCount >= 80% of maxPlayers
 * - Maintenance indicator with estimated completion time
 * - 4-20 server cards in Neo Brutalism grid with hover glow effect
 * - Loading skeleton and 10-second timeout with error/retry
 *
 * Integrates into Hero Section with online player count (30s update)
 *
 * @see Requirements 2.6, 2.7, 3.1, 3.2, 3.3, 3.4, 3.5, 3.6, 3.7, 3.8
 */
export function ServerStatusWidget({
  showOnlineCount = false,
  maxServers = 8,
}: ServerStatusWidgetProps) {
  const { subscribe, unsubscribe } = useSocket();
  const [servers, setServers] = useState<ServerStatusEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [totalOnlinePlayers, setTotalOnlinePlayers] = useState(0);
  const [lastUpdate, setLastUpdate] = useState<Date | null>(null);

  // Clamp maxServers to 4-20 range
  const displayLimit = Math.max(4, Math.min(20, maxServers));

  /**
   * Fetch server status from API
   * Implements 10-second timeout
   */
  const fetchServerStatus = useCallback(async () => {
    try {
      setError(null);
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 10000);

      const response = await fetch('/api/server-status', {
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        throw new Error(`Failed to fetch server status: ${response.statusText}`);
      }

      const data = await response.json();
      const serverList = Array.isArray(data) ? data : data.servers || [];

      // Limit to displayLimit servers
      const limitedServers = serverList.slice(0, displayLimit);
      setServers(limitedServers);

      // Calculate total online players
      const total = limitedServers.reduce((sum, server) => sum + server.playerCount, 0);
      setTotalOnlinePlayers(total);
      setLastUpdate(new Date());
      setLoading(false);
    } catch (err) {
      if (err instanceof Error && err.name === 'AbortError') {
        setError('Server status request timed out. Please try again.');
      } else {
        setError('Failed to load server status. Please try again.');
      }
      setLoading(false);
    }
  }, [displayLimit]);

  /**
   * Subscribe to realtime server status updates via websocket
   * Falls back to polling if websocket unavailable
   */
  useEffect(() => {
    // Initial fetch
    fetchServerStatus();

    // Subscribe to realtime updates
    subscribe(SocketChannel.SERVER_STATUS);

    // Set up polling for 30-second updates (for hero section online count)
    const pollInterval = setInterval(() => {
      fetchServerStatus();
    }, 30000);

    return () => {
      clearInterval(pollInterval);
      unsubscribe(SocketChannel.SERVER_STATUS);
    };
  }, [fetchServerStatus, subscribe, unsubscribe]);

  /**
   * Get status badge color and icon
   */
  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'online':
        return {
          color: '#22c55e',
          label: 'Online',
          icon: '●',
        };
      case 'busy':
        return {
          color: '#f59e0b',
          label: 'Busy',
          icon: '●',
        };
      case 'maintenance':
        return {
          color: '#ef4444',
          label: 'Maintenance',
          icon: '⚙',
        };
      case 'offline':
        return {
          color: '#6b7280',
          label: 'Offline',
          icon: '●',
        };
      default:
        return {
          color: '#6b7280',
          label: 'Unknown',
          icon: '?',
        };
