            style={{
              height: '200px',
              borderRadius: '0px',
            }}
          />
        ))}
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div
        style={{
          padding: '24px',
          textAlign: 'center',
          border: '2px solid #ef4444',
          borderRadius: '0px',
          background: 'rgba(239, 68, 68, 0.05)',
        }}
      >
        <p style={{ color: '#ef4444', margin: '0 0 16px 0' }}>{error}</p>
        <button
          onClick={() => {
            setLoading(true);
            fetchServerStatus();
          }}
          style={{
            padding: '8px 24px',
            background: '#ef4444',
            color: '#ffffff',
            border: 'none',
            borderRadius: '0px',
            cursor: 'pointer',
            fontSize: '12px',
            fontWeight: 600,
            textTransform: 'uppercase',
