          onMouseLeave={(e) => {
            e.currentTarget.style.background = '#ef4444';
            e.currentTarget.style.transform = 'translateY(0)';
          }}
        >
          Retry
        </button>
      </div>
    );
  }

  // Empty state
  if (servers.length === 0) {
    return (
      <div
        style={{
          padding: '24px',
          textAlign: 'center',
          border: '2px solid #2B2B2B',
