                    border: `1px solid ${statusInfo.color}`,
                    borderRadius: '0px',
                  }}
                >
                  <span
                    style={{
                      fontSize: '12px',
                      color: statusInfo.color,
                      fontWeight: 600,
                    }}
                  >
                    {statusInfo.icon}
                  </span>
                  <span
                    style={{
                      fontSize: '11px',
                      color: statusInfo.color,
                      fontWeight: 600,
                      textTransform: 'uppercase',
                      letterSpacing: '0.05em',
                    }}
                  >
                    {statusInfo.label}
                  </span>
                </div>
              </div>

              {/* Player count and capacity */}
              <div
                style={{
                  marginBottom: '12px',
                }}
              >
                <div
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    marginBottom: '6px',
                    fontSize: '12px',
                  }}
                >
