                    }}
                  />
                </div>
              </div>

              {/* Ping */}
              <div
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  fontSize: '12px',
                  marginBottom: '12px',
                }}
              >
                <span style={{ color: '#B0B0B0' }}>Ping</span>
                <span
                  style={{
                    color: server.ping < 50 ? '#22c55e' : server.ping < 100 ? '#f59e0b' : '#ef4444',
                    fontWeight: 600,
                  }}
                >
                  {server.ping}ms
                </span>
              </div>

              {/* Maintenance info */}
              {server.status === 'maintenance' && server.maintenanceETA && (
                <div
                  style={{
                    padding: '8px 12px',
                    background: 'rgba(239, 68, 68, 0.1)',
                    border: '1px solid rgba(239, 68, 68, 0.3)',
                    borderRadius: '0px',
                    fontSize: '11px',
                    color: '#ef4444',
                  }}
                >
                  <strong>ETA:</strong> {new Date(server.maintenanceETA).toLocaleString()}
                </div>
              )}

              {server.status === 'maintenance' && !server.maintenanceETA && (
                <div
                  style={{
                    padding: '8px 12px',
                    background: 'rgba(239, 68, 68, 0.1)',
                    border: '1px solid rgba(239, 68, 68, 0.3)',
                    borderRadius: '0px',
                    fontSize: '11px',
                    color: '#ef4444',
                  }}
                >
                  Completion time not yet determined
                </div>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

