import { describe, it, expect } from 'vitest';
import fc from 'fast-check';

/**
 * Property-Based Tests for Server Status Widget
 *
 * Property 3: Server Busy Status Computation
 * Property 4: Server Status Display Completeness
 *
 * Validates: Requirements 3.1, 3.2
 */

// ─── Arbitraries ──────────────────────────────────────────────────────

/** Generate a valid server status event */
const serverStatusEventArb = fc.record({
  serverId: fc.uuid(),
  name: fc.string({ minLength: 1, maxLength: 100 }),
  status: fc.constantFrom('online', 'offline', 'busy', 'maintenance'),
  playerCount: fc.integer({ min: 0, max: 10000 }),
  maxPlayers: fc.integer({ min: 1, max: 10000 }),
  ping: fc.integer({ min: 0, max: 999 }),
  maintenanceETA: fc.option(fc.date().map(d => d.toISOString())),
});

/** Generate a server that should be marked as busy (playerCount >= 80% of maxPlayers) */
const busyServerArb = fc.tuple(
  fc.integer({ min: 1, max: 10000 }),
  fc.integer({ min: 0, max: 1 }) // 0 or 1 to control exact threshold
).map(([maxPlayers, offset]) => ({
  serverId: fc.sample(fc.uuid(), 1)[0],
  name: fc.sample(fc.string({ minLength: 1, maxLength: 100 }), 1)[0],
  status: 'online' as const,
  playerCount: Math.floor(maxPlayers * 0.8) + offset,
  maxPlayers,
  ping: fc.sample(fc.integer({ min: 0, max: 999 }), 1)[0],
}));

/** Generate a server that should NOT be marked as busy (playerCount < 80% of maxPlayers) */
const notBusyServerArb = fc.tuple(
  fc.integer({ min: 1, max: 10000 }),
  fc.integer({ min: 0, max: 1 })
).map(([maxPlayers, offset]) => ({
  serverId: fc.sample(fc.uuid(), 1)[0],
  name: fc.sample(fc.string({ minLength: 1, maxLength: 100 }), 1)[0],
  status: 'online' as const,
  playerCount: Math.max(0, Math.floor(maxPlayers * 0.8) - 1 - offset),
  maxPlayers,
  ping: fc.sample(fc.integer({ min: 0, max: 999 }), 1)[0],
}));

// ─── Property 3: Server Busy Status Computation ────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 3: Server Busy Status Computation', () => {
  /**
   * **Validates: Requirements 3.1, 3.2**
   *
   * A server SHALL be marked as "busy" when playerCount >= 80% of maxPlayers.
   * This property verifies that the busy status computation is correct across
   * all valid server configurations.
   */

  it('server with playerCount >= 80% of maxPlayers should be marked as busy', () => {
    fc.assert(
      fc.property(
        fc.tuple(
          fc.integer({ min: 1, max: 10000 }),
          fc.integer({ min: 0, max: 1 })
        ),
        ([maxPlayers, offset]) => {
          const playerCount = Math.floor(maxPlayers * 0.8) + offset;
          const isBusy = playerCount >= maxPlayers * 0.8;

          expect(isBusy).toBe(true);
        }
      ),
      { numRuns: 100 }
    );
  });

  it('server with playerCount < 80% of maxPlayers should NOT be marked as busy', () => {
    fc.assert(
      fc.property(
        fc.tuple(
          fc.integer({ min: 1, max: 10000 }),
          fc.integer({ min: 0, max: 1 })
        ),
        ([maxPlayers, offset]) => {
          const playerCount = Math.max(0, Math.floor(maxPlayers * 0.8) - 1 - offset);
          const isBusy = playerCount >= maxPlayers * 0.8;

          expect(isBusy).toBe(false);
        }
      ),
      { numRuns: 100 }
    );
  });

  it('busy status threshold is exactly at 80% capacity', () => {
    fc.assert(
      fc.property(fc.integer({ min: 1, max: 10000 }), (maxPlayers) => {
        const threshold = maxPlayers * 0.8;
        const justBelowThreshold = threshold - 0.01;
        const justAtThreshold = threshold;
        const justAboveThreshold = threshold + 0.01;

        const isBelowBusy = justBelowThreshold < threshold;
        const isAtBusy = justAtThreshold >= threshold;
        const isAboveBusy = justAboveThreshold >= threshold;

        expect(isBelowBusy).toBe(true);
        expect(isAtBusy).toBe(true);
        expect(isAboveBusy).toBe(true);
      }),
      { numRuns: 100 }
    );
  });

  it('busy status is independent of server name, ping, or other fields', () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 1, max: 10000 }),
        fc.string({ minLength: 1, maxLength: 100 }),
        fc.integer({ min: 0, max: 999 }),
        (maxPlayers, name, ping) => {
          const playerCount = Math.floor(maxPlayers * 0.8);
          const isBusy = playerCount >= maxPlayers * 0.8;

          // Changing name or ping should not affect busy status
          expect(isBusy).toBe(true);
        }
      ),
      { numRuns: 100 }
    );
  });
});

// ─── Property 4: Server Status Display Completeness ────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 4: Server Status Display Completeness', () => {
  /**
   * **Validates: Requirements 3.2**
   *
   * Every server status display SHALL have all required fields populated:
   * name (non-empty), status (valid enum), playerCount (>= 0), and ping (>= 0).
   */

  it('every valid server status event has all required fields', () => {
    fc.assert(
      fc.property(serverStatusEventArb, (event) => {
        const hasName = event.name.length > 0;
        const hasValidStatus = ['online', 'offline', 'busy', 'maintenance'].includes(event.status);
        const hasValidPlayerCount = event.playerCount >= 0;
        const hasValidPing = event.ping >= 0;

        expect(hasName).toBe(true);
        expect(hasValidStatus).toBe(true);
        expect(hasValidPlayerCount).toBe(true);
        expect(hasValidPing).toBe(true);
      }),
      { numRuns: 100 }
    );
  });

  it('server status event with empty name is incomplete', () => {
    fc.assert(
      fc.property(
        fc.record({
          serverId: fc.uuid(),
          name: fc.constant(''),
          status: fc.constantFrom('online', 'offline', 'busy', 'maintenance'),
          playerCount: fc.integer({ min: 0, max: 10000 }),
          maxPlayers: fc.integer({ min: 1, max: 10000 }),
          ping: fc.integer({ min: 0, max: 999 }),
        }),
        (event) => {
          const isComplete = event.name.length > 0;
          expect(isComplete).toBe(false);
        }
      ),
      { numRuns: 50 }
    );
  });

  it('server status event with negative playerCount is incomplete', () => {
    fc.assert(
      fc.property(
        fc.record({
          serverId: fc.uuid(),
          name: fc.string({ minLength: 1, maxLength: 100 }),
          status: fc.constantFrom('online', 'offline', 'busy', 'maintenance'),
          playerCount: fc.integer({ min: -10000, max: -1 }),
          maxPlayers: fc.integer({ min: 1, max: 10000 }),
          ping: fc.integer({ min: 0, max: 999 }),
        }),
        (event) => {
          const isComplete = event.playerCount >= 0;
          expect(isComplete).toBe(false);
        }
      ),
      { numRuns: 50 }
    );
  });

  it('server status event with negative ping is incomplete', () => {
    fc.assert(
      fc.property(
        fc.record({
          serverId: fc.uuid(),
          name: fc.string({ minLength: 1, maxLength: 100 }),
          status: fc.constantFrom('online', 'offline', 'busy', 'maintenance'),
          playerCount: fc.integer({ min: 0, max: 10000 }),
          maxPlayers: fc.integer({ min: 1, max: 10000 }),
          ping: fc.integer({ min: -10000, max: -1 }),
        }),
        (event) => {
          const isComplete = event.ping >= 0;
          expect(isComplete).toBe(false);
        }
      ),
      { numRuns: 50 }
    );
  });

  it('server status event with invalid status enum is incomplete', () => {
    fc.assert(
      fc.property(
        fc.record({
          serverId: fc.uuid(),
          name: fc.string({ minLength: 1, maxLength: 100 }),
          status: fc.stringOf(fc.char()),
          playerCount: fc.integer({ min: 0, max: 10000 }),
          maxPlayers: fc.integer({ min: 1, max: 10000 }),
          ping: fc.integer({ min: 0, max: 999 }),
        }),
        (event) => {
          const validStatuses = ['online', 'offline', 'busy', 'maintenance'];
          const isComplete = validStatuses.includes(event.status);

          // Only check if status is not one of the valid values
          if (!validStatuses.includes(event.status)) {
            expect(isComplete).toBe(false);
          }
        }
      ),
      { numRuns: 50 }
    );
  });

  it('all required fields must be present for display completeness', () => {
    fc.assert(
      fc.property(serverStatusEventArb, (event) => {
        const isComplete =
          event.name.length > 0 &&
          ['online', 'offline', 'busy', 'maintenance'].includes(event.status) &&
          event.playerCount >= 0 &&
          event.ping >= 0;

        expect(isComplete).toBe(true);
      }),
      { numRuns: 100 }
    );
  });

  it('player count should never exceed maxPlayers in valid server state', () => {
    fc.assert(
      fc.property(
        fc.record({
          serverId: fc.uuid(),
          name: fc.string({ minLength: 1, maxLength: 100 }),
          status: fc.constantFrom('online', 'offline', 'busy', 'maintenance'),
          playerCount: fc.integer({ min: 0, max: 5000 }),
          maxPlayers: fc.integer({ min: 5001, max: 10000 }),
          ping: fc.integer({ min: 0, max: 999 }),
        }),
        (event) => {
          expect(event.playerCount).toBeLessThanOrEqual(event.maxPlayers);
        }
      ),
      { numRuns: 100 }
    );
  });

  it('ping latency should be within reasonable bounds (0-999ms)', () => {
    fc.assert(
      fc.property(serverStatusEventArb, (event) => {
        expect(event.ping).toBeGreaterThanOrEqual(0);
        expect(event.ping).toBeLessThanOrEqual(999);
      }),
      { numRuns: 100 }
    );
  });
});

import { NextResponse } from 'next/server';

/**
 * GET /api/server-status
 *
 * Returns the current status of all game servers.
 * This endpoint fetches data from the backend API and returns it to the client.
 *
 * @see Requirements 3.1, 3.2, 3.3, 3.4, 3.5, 3.6, 3.7, 3.8
 */
export async function GET() {
  try {
    // In production, this would call the actual backend API
    // For now, we'll return mock data that matches the expected format
    const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001';

    const response = await fetch(`${apiUrl}/server-status`, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
      },
      // Don't cache this endpoint - we want fresh data
      next: { revalidate: 0 },
    });

    if (!response.ok) {
      // Return mock data as fallback
      return NextResponse.json(getMockServerStatus(), { status: 200 });
    }

    const data = await response.json();
    return NextResponse.json(data, { status: 200 });
  } catch (error) {
    // Return mock data as fallback when backend is unavailable
    console.error('Failed to fetch server status from backend:', error);
    return NextResponse.json(getMockServerStatus(), { status: 200 });
  }
}

