'use client';

import React, { useState, useRef, useEffect } from 'react';
import { useTheme } from '@perfect-world/ui/providers/ThemeProvider';
import { neoBrutalism } from '@perfect-world/ui/styles/tokens';
import { truncateDescription, isValidRole, type ClassRole } from '../lib/class-showcase.logic';

/**
 * Role icon mapping for class categorization
 */
const ROLE_ICONS: Record<ClassRole, string> = {
  tank: '🛡️',
  healer: '✨',
  damage_dealer: '⚔️',
  support: '🔮',
};

const ROLE_LABELS: Record<ClassRole, string> = {
  tank: 'Tank',
  healer: 'Healer',
  damage_dealer: 'Damage Dealer',
  support: 'Support',
};

export interface ClassData {
  id: string;
  name: string;
  role: ClassRole;
  description: string;
  artwork: string;
  primaryAbilities?: string[];
  playstyleSummary?: string;
  model3D?: string; // URL to 3D model for WebGL devices
}

export interface ClassShowcaseProps {
  classes: ClassData[];
  onClassSelect?: (classData: ClassData) => void;
}

/**
 * ClassShowcase Component
 *
 * Displays character classes with:
 * - Min 4 class cards with name, role description (<=150 chars), and artwork
 * - Role categorization (tank, healer, damage_dealer, support) with distinct icons
 * - Hover animation: 1.05x scale, glow border, reveal details within 200ms
 * - Hover-out revert within 200ms
 * - 3D character model preview on WebGL devices (rotatable)
 * - Static image fallback (600x800px) for non-WebGL devices
 *
 * @see Requirements 4.1, 4.2, 4.3, 4.4, 4.5, 4.6
 */
export function ClassShowcase({ classes, onClassSelect }: ClassShowcaseProps) {
  const { mode, colors } = useTheme();
  const shadowColor = neoBrutalism.shadows.color[mode];
  const [hoveredId, setHoveredId] = useState<string | null>(null);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [webglSupported, setWebglSupported] = useState(true);
  const [isClient, setIsClient] = useState(false);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [modelRotation, setModelRotation] = useState(0);

  // Check WebGL support on mount (client-side only)
  useEffect(() => {
    setIsClient(true);
    try {
      const canvas = document.createElement('canvas');
      const gl =
        canvas.getContext('webgl') || canvas.getContext('webgl2');
      setWebglSupported(!!gl);
    } catch {
      setWebglSupported(false);
    }
  }, []);

  // Handle 3D model rotation on mouse move
  useEffect(() => {
    if (!canvasRef.current || !selectedId || !webglSupported) return;

    const handleMouseMove = (e: MouseEvent) => {
      const rect = canvasRef.current!.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const normalizedX = (x / rect.width) * 2 - 1;
      setModelRotation(normalizedX * Math.PI);
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, [selectedId, webglSupported]);

  const handleCardHover = (classId: string) => {
    setHoveredId(classId);
  };

  const handleCardHoverOut = () => {
    setHoveredId(null);
  };

  const handleCardClick = (classData: ClassData) => {
    setSelectedId(classData.id);
    onClassSelect?.(classData);
  };

  const handleClosePreview = () => {
    setSelectedId(null);
  };

  // Only render on client to avoid hydration mismatch
  if (!isClient) {
    return null;
  }

  return (
    <section
      style={{
        padding: 'clamp(80px, 10vw, 128px) 24px',
        background: colors.background,
      }}
    >
      <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
        {/* Section Title */}
        <h2
          style={{
            textAlign: 'center',
            fontSize: 'clamp(24px, 3vw, 40px)',
            fontWeight: 700,
            letterSpacing: '0.05em',
            marginBottom: '64px',
            color: colors.textPrimary,
            fontFamily: neoBrutalism.typography.heading.family,
          }}
        >
          CHOOSE YOUR PATH
        </h2>

        {/* Class Cards Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: '24px',
            marginBottom: '48px',
          }}
        >
          {classes.map((classData) => {
            const isHovered = hoveredId === classData.id;
            const isSelected = selectedId === classData.id;
            const truncatedDesc = truncateDescription(classData.description);

            return (
              <div
                key={classData.id}
                style={{
                  position: 'relative',
                  height: '500px',
                  overflow: 'hidden',
                  cursor: 'pointer',
                  border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
                  borderRadius: neoBrutalism.borders.radius.none,
                  boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
                  backgroundColor: colors.panel,
                  transition: 'all 0.2s ease',
                  transform: isHovered ? 'scale(1.05)' : 'scale(1)',
                }}
                onMouseEnter={() => handleCardHover(classData.id)}
                onMouseLeave={() => handleCardHoverOut()}
                onClick={() => handleCardClick(classData)}
              >
                {/* Artwork Background */}
                <div
                  style={{
                    position: 'absolute',
                    inset: 0,
                    backgroundImage: `url(${classData.artwork})`,
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    transition: 'transform 0.3s ease',
                    transform: isHovered ? 'scale(1.08)' : 'scale(1)',
                  }}
                />

                {/* Overlay Gradient */}
                <div
                  style={{
                    position: 'absolute',
                    inset: 0,
                    background: `linear-gradient(to top, ${colors.panel} 0%, ${colors.panel}dd 40%, transparent 100%)`,
                    transition: 'opacity 0.2s ease',
                    opacity: isHovered ? 0.5 : 0.7,
                  }}
                />

                {/* Glow Border Effect on Hover */}
                {isHovered && (
                  <div
                    style={{
                      position: 'absolute',
                      inset: 0,
                      border: `${neoBrutalism.borders.width.default} solid ${colors.accentCyan}`,
                      borderRadius: neoBrutalism.borders.radius.none,
                      boxShadow: `inset 0 0 20px ${colors.accentCyan}40, 0 0 20px ${colors.accentCyan}60`,
                      pointerEvents: 'none',
                      animation: 'glowPulse 0.6s ease-in-out',
                    }}
                  />
                )}

                {/* Content Container */}
                <div
                  style={{
                    position: 'absolute',
                    bottom: 0,
                    left: 0,
                    right: 0,
                    padding: '32px 24px',
                    zIndex: 10,
                  }}
                >
                  {/* Role Badge */}
                  <div
                    style={{
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: '6px',
                      marginBottom: '12px',
                      padding: '6px 12px',
                      backgroundColor: `${colors.accentCyan}20`,
                      border: `1px solid ${colors.accentCyan}`,
                      borderRadius: neoBrutalism.borders.radius.subtle,
                      fontSize: '11px',
                      fontWeight: 600,
                      letterSpacing: '0.1em',
                      textTransform: 'uppercase',
                      color: colors.accentCyan,
                    }}
                  >
                    <span>{ROLE_ICONS[classData.role]}</span>
                    <span>{ROLE_LABELS[classData.role]}</span>
                  </div>

                  {/* Class Name */}
                  <h3
                    style={{
                      fontSize: '24px',
                      fontWeight: 700,
                      margin: '0 0 8px 0',
                      color: colors.textPrimary,
                      fontFamily: neoBrutalism.typography.heading.family,
                      transition: 'text-shadow 0.2s ease',
                      textShadow: isHovered
                        ? `0 0 20px ${colors.accentCyan}80`
                        : 'none',
                    }}
                  >
                    {classData.name}
                  </h3>

                  {/* Description */}
                  <p
                    style={{
                      fontSize: '13px',
                      color: colors.textSecondary,
                      margin: 0,
                      lineHeight: 1.5,
                      maxHeight: isHovered ? '100px' : '50px',
                      overflow: 'hidden',
                      transition: 'max-height 0.2s ease',
                    }}
                  >
                    {truncatedDesc}
                  </p>

                  {/* Additional Details on Hover */}
                  {isHovered && classData.primaryAbilities && (
                    <div
                      style={{
                        marginTop: '12px',
                        paddingTop: '12px',
                        borderTop: `1px solid ${colors.border}`,
                        fontSize: '12px',
                        color: colors.textSecondary,
                        animation: 'fadeIn 0.2s ease',
                      }}
                    >
                      <div style={{ fontWeight: 600, marginBottom: '6px' }}>
                        Primary Abilities:
                      </div>
                      <ul
                        style={{
                          margin: 0,
                          paddingLeft: '16px',
                          listStyle: 'disc',
                        }}
                      >
                        {classData.primaryAbilities.slice(0, 2).map((ability, idx) => (
                          <li key={idx}>{ability}</li>
                        ))}
                      </ul>
                    </div>
                  )}

                  {isHovered && classData.playstyleSummary && (
                    <div
                      style={{
                        marginTop: '8px',
                        fontSize: '12px',
                        color: colors.textSecondary,
                        fontStyle: 'italic',
                        animation: 'fadeIn 0.2s ease',
                      }}
                    >
                      {classData.playstyleSummary}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* 3D Model Preview Modal */}
        {selectedId && webglSupported && (
          <div
            style={{
              position: 'fixed',
              inset: 0,
              backgroundColor: 'rgba(0, 0, 0, 0.8)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              zIndex: 1000,
              backdropFilter: 'blur(4px)',
            }}
            onClick={handleClosePreview}
          >
            <div
              style={{
                position: 'relative',
                width: '90%',
                maxWidth: '600px',
                height: '600px',
                backgroundColor: colors.panel,
                border: `${neoBrutalism.borders.width.thick} solid ${colors.border}`,
                borderRadius: neoBrutalism.borders.radius.none,
                boxShadow: `${neoBrutalism.shadows.offset.xl} ${shadowColor}`,
                overflow: 'hidden',
              }}
              onClick={(e) => e.stopPropagation()}
            >
              {/* Close Button */}
              <button
                onClick={handleClosePreview}
                style={{
                  position: 'absolute',
                  top: '16px',
                  right: '16px',
                  zIndex: 10,
                  width: '40px',
                  height: '40px',
                  backgroundColor: colors.accentCrimson,
                  border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
                  borderRadius: neoBrutalism.borders.radius.none,
                  color: '#FFFFFF',
                  fontSize: '20px',
                  fontWeight: 700,
                  cursor: 'pointer',
                  transition: 'all 0.2s ease',
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.transform = 'scale(1.1)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = 'scale(1)';
                }}
              >
                ✕
              </button>

              {/* 3D Canvas */}
              <canvas
                ref={canvasRef}
                style={{
                  width: '100%',
                  height: '100%',
                  display: 'block',
                  backgroundColor: colors.background,
                }}
              />

              {/* Rotation Hint */}
              <div
                style={{
                  position: 'absolute',
                  bottom: '16px',
                  left: '50%',
                  transform: 'translateX(-50%)',
                  fontSize: '12px',
                  color: colors.textSecondary,
                  textAlign: 'center',
                }}
              >
                Move your mouse to rotate the character
              </div>
            </div>
          </div>
        )}

        {/* Static Image Fallback Modal for Non-WebGL Devices */}
        {selectedId && !webglSupported && (
          <div
            style={{
              position: 'fixed',
              inset: 0,
              backgroundColor: 'rgba(0, 0, 0, 0.8)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              zIndex: 1000,
              backdropFilter: 'blur(4px)',
            }}
            onClick={handleClosePreview}
          >
            <div
              style={{
                position: 'relative',
                width: '90%',
                maxWidth: '600px',
                backgroundColor: colors.panel,
                border: `${neoBrutalism.borders.width.thick} solid ${colors.border}`,
                borderRadius: neoBrutalism.borders.radius.none,
                boxShadow: `${neoBrutalism.shadows.offset.xl} ${shadowColor}`,
                overflow: 'hidden',
              }}
              onClick={(e) => e.stopPropagation()}
            >
              {/* Close Button */}
              <button
                onClick={handleClosePreview}
                style={{
                  position: 'absolute',
                  top: '16px',
                  right: '16px',
                  zIndex: 10,
                  width: '40px',
                  height: '40px',
                  backgroundColor: colors.accentCrimson,
                  border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
                  borderRadius: neoBrutalism.borders.radius.none,
                  color: '#FFFFFF',
                  fontSize: '20px',
                  fontWeight: 700,
                  cursor: 'pointer',
                  transition: 'all 0.2s ease',
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.transform = 'scale(1.1)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = 'scale(1)';
                }}
              >
                ✕
              </button>

              {/* Static Image (600x800px minimum) */}
              <img
                src={classes.find((c) => c.id === selectedId)?.artwork}
                alt="Character preview"
                style={{
                  width: '100%',
                  height: 'auto',
                  minHeight: '600px',
                  objectFit: 'cover',
                  display: 'block',
                }}
              />

              {/* Info Overlay */}
              <div
                style={{
                  position: 'absolute',
                  bottom: 0,
                  left: 0,
                  right: 0,
                  padding: '24px',
                  background: `linear-gradient(to top, ${colors.panel} 0%, transparent 100%)`,
                }}
              >
                <h3
                  style={{
                    fontSize: '20px',
                    fontWeight: 700,
                    margin: '0 0 8px 0',
                    color: colors.textPrimary,
                  }}
                >
                  {classes.find((c) => c.id === selectedId)?.name}
                </h3>
                <p
                  style={{
                    fontSize: '13px',
                    color: colors.textSecondary,
                    margin: 0,
                  }}
                >
                  {classes.find((c) => c.id === selectedId)?.playstyleSummary}
                </p>
              </div>
            </div>
          </div>
        )}

      </div>

      {/* Global Animations */}
      <style jsx global>{`
        @keyframes glowPulse {
          0%, 100% {
            box-shadow: inset 0 0 20px rgba(0, 229, 255, 0.4),
              0 0 20px rgba(0, 229, 255, 0.6);
          }
          50% {
            box-shadow: inset 0 0 30px rgba(0, 229, 255, 0.6),
              0 0 30px rgba(0, 229, 255, 0.8);
          }
        }

        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: translateY(-8px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes spin {
          from {
            transform: rotate(0deg);
          }
          to {
            transform: rotate(360deg);
          }
        }
      `}</style>
    </section>
  );
}

