'use client';

import React from 'react';
import Link from 'next/link';

interface RankingEntry {
  rank: number;
  name: string;
  score: number;
  guild: string | null;
}

interface RankingsPreviewProps {
  category: 'players' | 'guilds' | 'pvp' | 'economy';
  entries: RankingEntry[];
  scoreLabel: string;
}

function getRankStyle(rank: number): React.CSSProperties {
  switch (rank) {
    case 1:
      return { color: '#ffd700', textShadow: '0 0 8px rgba(255, 215, 0, 0.5)', fontWeight: 'bold' };
    case 2:
      return { color: '#C0C0C0', textShadow: '0 0 8px rgba(192, 192, 192, 0.4)', fontWeight: 'bold' };
    case 3:
      return { color: '#CD7F32', textShadow: '0 0 8px rgba(205, 127, 50, 0.4)', fontWeight: 'bold' };
    default:
      return { color: '#8b8ba3', fontWeight: 'bold' };
  }
}

function formatScore(score: number): string {
  return score.toLocaleString();
}

export function RankingsPreview({ category, entries, scoreLabel }: RankingsPreviewProps) {
  const topEntries = entries.slice(0, 10);

  return (
    <div
      style={{
        backgroundColor: '#12121a',
        border: '2px solid #2a2a3a',
        boxShadow: '0 4px 20px rgba(0, 0, 0, 0.4)',
        overflow: 'hidden',
      }}
    >
      {/* Table */}
      <div style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', minWidth: '600px', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ backgroundColor: '#1a1a2e', borderBottom: '2px solid #2a2a3a' }}>
              <th
                style={{
                  padding: '12px 16px',
                  textAlign: 'left',
                  fontSize: '12px',
                  fontWeight: 600,
                  letterSpacing: '0.1em',
                  textTransform: 'uppercase',
                  color: '#8b8ba3',
                }}
              >
                Rank
              </th>
              <th
                style={{
                  padding: '12px 16px',
                  textAlign: 'left',
                  fontSize: '12px',
                  fontWeight: 600,
                  letterSpacing: '0.1em',
                  textTransform: 'uppercase',
                  color: '#8b8ba3',
                }}
              >
                Name
              </th>
              <th
                style={{
                  padding: '12px 16px',
                  textAlign: 'left',
                  fontSize: '12px',
                  fontWeight: 600,
                  letterSpacing: '0.1em',
                  textTransform: 'uppercase',
                  color: '#8b8ba3',
                }}
              >
                {scoreLabel}
              </th>
              <th
                style={{
                  padding: '12px 16px',
                  textAlign: 'left',
                  fontSize: '12px',
                  fontWeight: 600,
                  letterSpacing: '0.1em',
                  textTransform: 'uppercase',
                  color: '#8b8ba3',
                }}
              >
                Guild
              </th>
            </tr>
          </thead>
          <tbody>
            {topEntries.map((entry, index) => (
              <tr
                key={entry.rank}
                style={{
                  backgroundColor: index % 2 === 0 ? '#12121a' : '#0f0f18',
                  borderBottom: '2px solid #2a2a3a',
                  transition: 'all 0.2s ease',
                  cursor: 'pointer',
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.backgroundColor = 'rgba(0, 229, 255, 0.08)';
                  e.currentTarget.style.boxShadow = 'inset 0 0 12px rgba(0, 229, 255, 0.1)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.backgroundColor = index % 2 === 0 ? '#12121a' : '#0f0f18';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                <td style={{ padding: '12px 16px', fontSize: '16px', ...getRankStyle(entry.rank) }}>
                  #{entry.rank}
                </td>
                <td style={{ padding: '12px 16px', fontSize: '14px', fontWeight: 600, color: '#ffffff' }}>
                  {entry.name}
                </td>
                <td style={{ padding: '12px 16px', fontSize: '13px', fontFamily: 'monospace', color: '#00e5ff' }}>
                  {formatScore(entry.score)}
                </td>
                <td style={{ padding: '12px 16px', fontSize: '13px', color: '#8b8ba3' }}>
                  {entry.guild ?? <span style={{ fontStyle: 'italic', opacity: 0.6 }}>No Guild</span>}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Footer with link to full rankings */}
      <div
        style={{
          padding: '16px',
          borderTop: '2px solid #2a2a3a',
          display: 'flex',
          justifyContent: 'flex-end',
          backgroundColor: '#0f0f18',
        }}
      >
        <Link
          href="/rankings"
          style={{
            fontSize: '13px',
            fontWeight: 600,
            letterSpacing: '0.05em',
            textTransform: 'uppercase',
            color: '#00e5ff',
            textDecoration: 'none',
            transition: 'all 0.2s ease',
            padding: '8px 16px',
            border: '1px solid #00e5ff',
            display: 'inline-block',
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.boxShadow = '0 0 12px rgba(0, 229, 255, 0.3)';
            e.currentTarget.style.backgroundColor = 'rgba(0, 229, 255, 0.1)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.boxShadow = 'none';
            e.currentTarget.style.backgroundColor = 'transparent';
          }}
        >
          View Full Rankings →
        </Link>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import Link from 'next/link';

type NewsCategory = 'Patch Notes' | 'Events' | 'Community' | 'Announcements';

interface NewsArticle {
  id: number;
  title: string;
  excerpt: string;
  date: string;
  category: NewsCategory;
  featured?: boolean;
}

interface NewsPreviewProps {
  articles: NewsArticle[];
}

const CATEGORY_COLORS: Record<NewsCategory, string> = {
  'Patch Notes': '#00e5ff',
  Events: '#b44aff',
  Community: '#ffd700',
  Announcements: '#ff3366',
};

function formatDate(dateStr: string): string {
  const date = new Date(dateStr);
  return date.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
  });
}

function truncateExcerpt(text: string, maxLength: number = 200): string {
  if (text.length <= maxLength) return text;
  return text.slice(0, maxLength) + '...';
}

export function NewsPreview({ articles }: NewsPreviewProps) {
  const [hoveredCardId, setHoveredCardId] = useState<number | null>(null);

  // Get featured article (first one marked as featured, or first article)
  const featuredArticle = articles.find((a) => a.featured) || articles[0];
  
  // Get remaining articles for grid (max 6 total, so max 5 in grid if featured is separate)
  const gridArticles = featuredArticle
    ? articles
        .filter((a) => a.id !== featuredArticle.id)
        .slice(0, 5)
    : articles.slice(0, 6);

  return (
    <div>
      {/* Featured Article Hero Card */}
      {featuredArticle && (
        <div
          style={{
            marginBottom: '32px',
            overflow: 'hidden',
            transition: 'all 0.3s ease',
            backgroundColor: '#12121a',
            border: '2px solid #2a2a3a',
            cursor: 'pointer',
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.boxShadow = '0 0 30px rgba(0, 229, 255, 0.15), 0 0 60px rgba(180, 74, 255, 0.08)';
            e.currentTarget.style.borderColor = '#00e5ff';
            e.currentTarget.style.transform = 'translateY(-2px)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.boxShadow = 'none';
            e.currentTarget.style.borderColor = '#2a2a3a';
            e.currentTarget.style.transform = 'translateY(0)';
          }}
        >
          {/* Featured Image Placeholder */}
          <div
            style={{
              width: '100%',
              height: '300px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              background: `linear-gradient(135deg, ${CATEGORY_COLORS[featuredArticle.category]}, #12121a)`,
              fontSize: '24px',
              fontWeight: 700,
              textTransform: 'uppercase',
              color: 'rgba(255, 255, 255, 0.6)',
            }}
          >
            Featured
          </div>

          {/* Featured Content */}
          <div style={{ padding: '24px 32px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '12px' }}>
              <span
                style={{
                  padding: '6px 12px',
                  fontSize: '11px',
                  fontWeight: 700,
                  letterSpacing: '0.1em',
                  textTransform: 'uppercase',
                  backgroundColor: CATEGORY_COLORS[featuredArticle.category],
                  color: '#0a0a0f',
                  border: `1px solid ${CATEGORY_COLORS[featuredArticle.category]}`,
                  boxShadow: `0 0 8px ${CATEGORY_COLORS[featuredArticle.category]}66`,
                }}
              >
                {featuredArticle.category}
              </span>
              <time
                style={{
                  fontSize: '13px',
                  color: '#8b8ba3',
                }}
                dateTime={featuredArticle.date}
              >
                {formatDate(featuredArticle.date)}
              </time>
            </div>

            <h2
              style={{
                fontSize: 'clamp(20px, 2vw, 28px)',
                fontWeight: 700,
                letterSpacing: '0.02em',
                textTransform: 'uppercase',
                color: '#ffffff',
                margin: '0 0 12px 0',
                lineHeight: 1.3,
              }}
            >
              {featuredArticle.title}
            </h2>

            <p
              style={{
                fontSize: '15px',
                lineHeight: 1.6,
                color: '#8b8ba3',
                margin: 0,
              }}
            >
              {truncateExcerpt(featuredArticle.excerpt, 200)}
            </p>
          </div>
        </div>
      )}

      {/* News Grid (max 6 cards total, or 5 if featured is shown separately) */}
      {gridArticles.length > 0 && (
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: '20px',
          }}
        >
          {gridArticles.map((article) => (
            <div
              key={article.id}
              style={{
                display: 'flex',
                flexDirection: 'column',
                overflow: 'hidden',
                transition: 'all 0.3s ease',
                backgroundColor: '#12121a',
                border: '2px solid #2a2a3a',
                borderTop: `3px solid ${CATEGORY_COLORS[article.category]}`,
                cursor: 'pointer',
                transform: hoveredCardId === article.id ? 'translateY(-8px)' : 'translateY(0)',
                boxShadow:
                  hoveredCardId === article.id
                    ? `0 0 20px ${CATEGORY_COLORS[article.category]}33, 0 0 40px ${CATEGORY_COLORS[article.category]}1a`
                    : 'none',
              }}
              onMouseEnter={() => setHoveredCardId(article.id)}
              onMouseLeave={() => setHoveredCardId(null)}
            >
              {/* Card Image Placeholder */}
              <div
                style={{
                  width: '100%',
                  height: '160px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  background: `linear-gradient(135deg, ${CATEGORY_COLORS[article.category]}, #12121a)`,
                  fontSize: '14px',
                  fontWeight: 600,
                  textTransform: 'uppercase',
                  color: 'rgba(255, 255, 255, 0.5)',
                }}
              >
                {article.category}
              </div>

              {/* Card Content */}
              <div style={{ padding: '16px', display: 'flex', flexDirection: 'column', flex: 1 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' }}>
                  <span
                    style={{
                      padding: '4px 8px',
                      fontSize: '10px',
                      fontWeight: 700,
                      letterSpacing: '0.08em',
                      textTransform: 'uppercase',
                      backgroundColor: CATEGORY_COLORS[article.category],
                      color: '#0a0a0f',
                      border: `1px solid ${CATEGORY_COLORS[article.category]}`,
                    }}
                  >
                    {article.category}
                  </span>
                  <time
                    style={{
                      fontSize: '11px',
                      color: '#8b8ba3',
                    }}
                    dateTime={article.date}
                  >
                    {formatDate(article.date)}
                  </time>
                </div>

                <h3
                  style={{
                    fontSize: '15px',
                    fontWeight: 700,
                    letterSpacing: '0.02em',
                    textTransform: 'uppercase',
                    color: '#ffffff',
                    margin: '0 0 8px 0',
                    lineHeight: 1.3,
                  }}
                >
                  {article.title}
                </h3>

                <p
                  style={{
                    fontSize: '13px',
                    lineHeight: 1.5,
                    color: '#8b8ba3',
                    margin: 0,
                    flex: 1,
                  }}
                >
                  {truncateExcerpt(article.excerpt, 150)}
                </p>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* View All News Link */}
      <div
        style={{
          marginTop: '32px',
          textAlign: 'center',
        }}
      >
        <Link
          href="/news"
          style={{
            display: 'inline-block',
            padding: '12px 32px',
            fontSize: '13px',
            fontWeight: 600,
            letterSpacing: '0.1em',
            textTransform: 'uppercase',
            color: '#00e5ff',
            textDecoration: 'none',
            border: '2px solid #00e5ff',
            backgroundColor: 'transparent',
            transition: 'all 0.3s ease',
            cursor: 'pointer',
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.backgroundColor = 'rgba(0, 229, 255, 0.1)';
            e.currentTarget.style.boxShadow = '0 0 20px rgba(0, 229, 255, 0.3)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.backgroundColor = 'transparent';
            e.currentTarget.style.boxShadow = 'none';
          }}
        >
          View All News →
        </Link>
      </div>
    </div>
  );
}

