import { describe, it, expect } from 'vitest';
import fc from 'fast-check';
import { computeBackoffDelay, DEFAULT_BACKOFF_CONFIG } from './backoff';

/**
 * Property-Based Tests for Exponential Backoff Delay Computation
 *
 * Property 25: Exponential Backoff Delay Computation
 * Validates: Requirements 15.2
 */

// ─── Helpers / Arbitraries ────────────────────────────────────────────

/** Generate a valid attempt number (1 to maxAttempts) */
const validAttemptArb = fc.integer({ min: 1, max: DEFAULT_BACKOFF_CONFIG.maxAttempts });

/** Generate an invalid attempt number (exceeds maxAttempts) */
const overMaxAttemptArb = fc.integer({ min: DEFAULT_BACKOFF_CONFIG.maxAttempts + 1, max: 1000 });

/** Generate an invalid attempt number (below 1) */
const belowMinAttemptArb = fc.integer({ min: -1000, max: 0 });

/** Generate a pair of valid attempts where a <= b (for monotonicity check) */
const orderedAttemptPairArb = fc
  .tuple(validAttemptArb, validAttemptArb)
  .map(([a, b]) => (a <= b ? [a, b] : [b, a]) as [number, number]);

// ─── Property 25: Exponential Backoff Delay Computation ───────────────

describe('Feature: perfect-world-neo-brutalism, Property 25: Exponential Backoff Delay Computation', () => {
  /**
   * **Validates: Requirements 15.2**
   *
   * For any attempt N (1 <= N <= maxAttempts), the delay SHALL be computed as
   * min(baseDelay * 2^(N-1), maxDelay). The delay SHALL never exceed maxDelay,
   * SHALL always be >= baseDelay for valid attempts, and SHALL be monotonically
   * non-decreasing. Returns null for invalid attempts.
   */

  it('for attempt 1, delay is exactly baseDelay (1000ms)', () => {
    const delay = computeBackoffDelay(1);
    expect(delay).toBe(DEFAULT_BACKOFF_CONFIG.baseDelay);
  });

  it('for any attempt N, delay equals min(baseDelay * 2^(N-1), maxDelay)', () => {
    fc.assert(
      fc.property(validAttemptArb, (attempt) => {
        const delay = computeBackoffDelay(attempt);
        const expected = Math.min(
          DEFAULT_BACKOFF_CONFIG.baseDelay * Math.pow(DEFAULT_BACKOFF_CONFIG.factor, attempt - 1),
          DEFAULT_BACKOFF_CONFIG.maxDelay,
        );
        expect(delay).toBe(expected);
      }),
      { numRuns: 200 },
    );
  });

  it('delay never exceeds maxDelay (30000ms)', () => {
    fc.assert(
      fc.property(validAttemptArb, (attempt) => {
        const delay = computeBackoffDelay(attempt);
        expect(delay).not.toBeNull();
        expect(delay!).toBeLessThanOrEqual(DEFAULT_BACKOFF_CONFIG.maxDelay);
      }),
      { numRuns: 200 },
    );
  });

  it('delay is always >= baseDelay for valid attempts', () => {
    fc.assert(
      fc.property(validAttemptArb, (attempt) => {
        const delay = computeBackoffDelay(attempt);
        expect(delay).not.toBeNull();
        expect(delay!).toBeGreaterThanOrEqual(DEFAULT_BACKOFF_CONFIG.baseDelay);
      }),
      { numRuns: 200 },
    );
  });

  it('returns null for attempt > maxAttempts (10)', () => {
    fc.assert(
      fc.property(overMaxAttemptArb, (attempt) => {
        const delay = computeBackoffDelay(attempt);
        expect(delay).toBeNull();
      }),
      { numRuns: 200 },
    );
  });

  it('returns null for attempt < 1', () => {
    fc.assert(
      fc.property(belowMinAttemptArb, (attempt) => {
        const delay = computeBackoffDelay(attempt);
        expect(delay).toBeNull();
      }),
      { numRuns: 200 },
    );
  });

  it('delays are monotonically non-decreasing', () => {
    fc.assert(
      fc.property(orderedAttemptPairArb, ([a, b]) => {
        const delayA = computeBackoffDelay(a);
        const delayB = computeBackoffDelay(b);
        expect(delayA).not.toBeNull();
        expect(delayB).not.toBeNull();
        expect(delayB!).toBeGreaterThanOrEqual(delayA!);
      }),
      { numRuns: 200 },
    );
  });

  it('delay formula holds for custom configurations', () => {
    const configArb = fc.record({
      baseDelay: fc.integer({ min: 100, max: 5000 }),
      factor: fc.integer({ min: 2, max: 4 }),
      maxDelay: fc.integer({ min: 5000, max: 60000 }),
      maxAttempts: fc.integer({ min: 3, max: 20 }),
    });

    fc.assert(
      fc.property(configArb, (config) => {
        for (let attempt = 1; attempt <= config.maxAttempts; attempt++) {
          const delay = computeBackoffDelay(attempt, config);
          const expected = Math.min(
            config.baseDelay * Math.pow(config.factor, attempt - 1),
            config.maxDelay,
          );
          expect(delay).toBe(expected);
        }

        // Beyond maxAttempts returns null
        expect(computeBackoffDelay(config.maxAttempts + 1, config)).toBeNull();
        // Below 1 returns null
        expect(computeBackoffDelay(0, config)).toBeNull();
      }),
      { numRuns: 100 },
    );
  });
});

/**
 * Exponential backoff delay computation for websocket reconnection.
 *
 * Formula: min(baseDelay * 2^(attempt - 1), maxDelay)
 *
 * This is a pure function exported separately for property-based testing.
 */

export interface BackoffConfig {
  /** Base delay in milliseconds (default: 1000) */
  baseDelay: number;
  /** Multiplier factor (default: 2) */
  factor: number;
  /** Maximum delay cap in milliseconds (default: 30000) */
  maxDelay: number;
  /** Maximum number of reconnection attempts (default: 10) */
  maxAttempts: number;
}

export const DEFAULT_BACKOFF_CONFIG: BackoffConfig = {
  baseDelay: 1000,
  factor: 2,
  maxDelay: 30000,
  maxAttempts: 10,
};

/**
 * Computes the reconnection delay for a given attempt number.
 *
 * @param attempt - The attempt number (1-indexed, 1 <= attempt <= maxAttempts)
 * @param config - Backoff configuration parameters
 * @returns The delay in milliseconds, or null if attempt exceeds maxAttempts
 */
export function computeBackoffDelay(
  attempt: number,
  config: BackoffConfig = DEFAULT_BACKOFF_CONFIG,
): number | null {
  if (attempt < 1 || attempt > config.maxAttempts) {
    return null;
  }

  const delay = config.baseDelay * Math.pow(config.factor, attempt - 1);
  return Math.min(delay, config.maxDelay);
}

import { io, Socket } from 'socket.io-client';
import { computeBackoffDelay, DEFAULT_BACKOFF_CONFIG, type BackoffConfig } from './backoff';
import {
  type ConnectionState,
  type RealtimeClientConfig,
  type EventCallback,
  type SocketChannel,
  POLLABLE_CHANNELS,
} from './types';

/**
 * RealtimeClient wraps Socket.IO with:
 * - JWT-authenticated websocket connections (5s timeout)
 * - Exponential backoff reconnection (1s start, 2x factor, 30s max, 10 attempts)
 * - HTTP polling fallback after 10 failed attempts (30s interval)
 * - Degraded-mode state tracking
 */
export class RealtimeClient {
  private socket: Socket | null = null;
  private connectionState: ConnectionState = 'disconnected';
  private reconnectAttempt = 0;
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
  private pollingTimers: Map<string, ReturnType<typeof setInterval>> = new Map();
  private listeners: Map<string, Set<EventCallback>> = new Map();
  private subscribedChannels: Set<SocketChannel> = new Set();
  private backoffConfig: BackoffConfig = DEFAULT_BACKOFF_CONFIG;

  private readonly config: Required<RealtimeClientConfig>;

  constructor(config: RealtimeClientConfig) {
    this.config = {
      connectionTimeout: 5000,
      pollingInterval: 30000,
      ...config,
    };
  }

  /** Get the current connection state */
  getConnectionState(): ConnectionState {
    return this.connectionState;
  }

  /** Check if the client is in degraded (polling) mode */
  isDegraded(): boolean {
    return this.connectionState === 'degraded';
  }

  /** Connect to the websocket server */
  connect(): void {
    const token = this.config.getToken();
    if (!token) {
      this.setConnectionState('disconnected');
      return;
    }

    this.setConnectionState('connecting');
    this.reconnectAttempt = 0;

    this.socket = io(this.config.url, {
      auth: { token },
      timeout: this.config.connectionTimeout,
      reconnection: false, // We handle reconnection manually for backoff control
      transports: ['websocket'],
    });

    this.setupSocketListeners();
  }

  /** Disconnect from the websocket server and stop all polling */
  disconnect(): void {
    this.clearReconnectTimer();
    this.stopAllPolling();

    if (this.socket) {
      this.socket.removeAllListeners();
      this.socket.disconnect();
      this.socket = null;
    }

    this.setConnectionState('disconnected');
  }

  /** Subscribe to a channel */
  subscribe(channel: SocketChannel): void {
    this.subscribedChannels.add(channel);

    if (this.socket?.connected) {
      this.socket.emit('subscribe', channel);
    }

    // If in degraded mode, start polling for this channel if pollable
    if (this.connectionState === 'degraded' && POLLABLE_CHANNELS.includes(channel)) {
      this.startPollingForChannel(channel);
    }
  }

  /** Unsubscribe from a channel */
  unsubscribe(channel: SocketChannel): void {
    this.subscribedChannels.delete(channel);

    if (this.socket?.connected) {
      this.socket.emit('unsubscribe', channel);
    }

    this.stopPollingForChannel(channel);
  }

  /** Register an event listener */
  on<T = unknown>(event: string, callback: EventCallback<T>): void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(callback as EventCallback);

    // Also register on the socket if connected
    if (this.socket?.connected) {
      this.socket.on(event, callback as EventCallback);
    }
  }

  /** Remove an event listener */
  off<T = unknown>(event: string, callback: EventCallback<T>): void {
    const eventListeners = this.listeners.get(event);
    if (eventListeners) {
      eventListeners.delete(callback as EventCallback);
    }

    if (this.socket) {
      this.socket.off(event, callback as EventCallback);
    }
  }

  /** Emit data to listeners for a given event */
  private emit(event: string, data: unknown): void {
    const eventListeners = this.listeners.get(event);
    if (eventListeners) {
      eventListeners.forEach((cb) => cb(data));
    }
  }

  private setupSocketListeners(): void {
    if (!this.socket) return;

    this.socket.on('connect', () => {
      this.reconnectAttempt = 0;
      this.setConnectionState('connected');
      this.stopAllPolling();

      // Re-subscribe to all channels
      this.subscribedChannels.forEach((channel) => {
        this.socket!.emit('subscribe', channel);
      });

      // Re-register all event listeners on the socket
      this.listeners.forEach((callbacks, event) => {
        callbacks.forEach((cb) => {
          this.socket!.on(event, cb);
        });
      });
    });

    this.socket.on('disconnect', (reason) => {
      if (reason === 'io client disconnect') {
        // Intentional disconnect, don't reconnect
        return;
      }
      this.attemptReconnect();
    });

    this.socket.on('connect_error', () => {
      this.attemptReconnect();
    });
  }

  private attemptReconnect(): void {
    this.reconnectAttempt++;

    const delay = computeBackoffDelay(this.reconnectAttempt, this.backoffConfig);

    if (delay === null) {
      // Exhausted all reconnection attempts, fall back to polling
      this.enterDegradedMode();
      return;
    }

    this.setConnectionState('reconnecting');
    this.clearReconnectTimer();

    this.reconnectTimer = setTimeout(() => {
      const token = this.config.getToken();
      if (!token) {
        this.setConnectionState('disconnected');
        return;
      }

      // Clean up old socket
      if (this.socket) {
        this.socket.removeAllListeners();
        this.socket.disconnect();
      }

      // Create new connection attempt
      this.socket = io(this.config.url, {
        auth: { token },
        timeout: this.config.connectionTimeout,
        reconnection: false,
        transports: ['websocket'],
      });

      this.setupSocketListeners();
    }, delay);
  }

  private enterDegradedMode(): void {
    this.setConnectionState('degraded');

    // Start polling for all subscribed pollable channels
    this.subscribedChannels.forEach((channel) => {
      if (POLLABLE_CHANNELS.includes(channel)) {
        this.startPollingForChannel(channel);
      }
    });
  }

  private startPollingForChannel(channel: SocketChannel): void {
    // Don't start duplicate polling
    if (this.pollingTimers.has(channel)) return;

    // Immediately fetch once
    this.pollChannel(channel);

    // Then set up interval
    const timer = setInterval(() => {
      this.pollChannel(channel);
    }, this.config.pollingInterval);

    this.pollingTimers.set(channel, timer);
  }

  private stopPollingForChannel(channel: SocketChannel): void {
    const timer = this.pollingTimers.get(channel);
    if (timer) {
      clearInterval(timer);
      this.pollingTimers.delete(channel);
    }
  }

  private stopAllPolling(): void {
    this.pollingTimers.forEach((timer) => clearInterval(timer));
    this.pollingTimers.clear();
  }

  private async pollChannel(channel: SocketChannel): Promise<void> {
    try {
      const token = this.config.getToken();
      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
      };
      if (token) {
        headers['Authorization'] = `Bearer ${token}`;
      }

      const response = await fetch(
        `${this.config.apiBaseUrl}/realtime/poll/${channel}`,
        { headers },
      );

      if (response.ok) {
        const data = await response.json();
        this.emit(channel, data);
      }
    } catch {
      // Silently fail on polling errors - will retry on next interval
    }
  }

  private setConnectionState(state: ConnectionState): void {
    if (this.connectionState !== state) {
      this.connectionState = state;
      this.emit('connection-state-change', state);
    }
  }

  private clearReconnectTimer(): void {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
  }
}
